"""
Parameterized generator for GH397_napari_7053.

Source PR:    https://github.com/napari/napari/pull/7053
Source Issue: https://github.com/napari/napari/issues/5316

Seed varies: renames 'action_str' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH397_napari_7053'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH397_napari_7053'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('action_str', 'action_str' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH397_napari_7053',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'napari/napari',
                "pr_number": 7053,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/napari/napari/pull/7053",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'napari/settings/_migrations.py': 'from __future__ import annotations\n\nimport warnings\nfrom contextlib import contextmanager\nfrom importlib.metadata import distributions\nfrom typing import TYPE_CHECKING, Callable, NamedTuple\n\nfrom napari.settings._fields import Version\n\nif TYPE_CHECKING:\n    from napari.settings._napari_settings import NapariSettings\n\n_MIGRATORS: list[Migrator] = []\nMigratorF = Callable[[\'NapariSettings\'], None]\n\n\nclass Migrator(NamedTuple):\n    """Tuple of from-version, to-version, migrator function."""\n\n    from_: Version\n    to_: Version\n    run: MigratorF\n\n\ndef do_migrations(model: NapariSettings):\n    """Migrate (update) a NapariSettings model in place."""\n    for migration in sorted(_MIGRATORS, key=lambda m: m.from_):\n        if model.schema_version == migration.from_:\n            with mutation_allowed(model):\n                backup = model.dict()\n                try:\n                    migration.run(model)\n                    model.schema_version = migration.to_\n                except Exception as e:  # noqa BLE001\n                    msg = (\n                        f\'Failed to migrate settings from v{migration.from_} \'\n                        f\'to v{migration.to_}. Error: {e}. \'\n                    )\n                    try:\n                        model.update(backup)\n                        msg += \'You may need to reset your settings with `napari --reset`. \'\n                    except Exception:  # noqa BLE001\n                        msg += \'Settings rollback also failed. Please run `napari --reset`.\'\n                    warnings.warn(msg)\n                    return\n    model._maybe_save()\n\n\n@contextmanager\ndef mutation_allowed(obj: NapariSettings):\n    """Temporarily allow mutations on an immutable model."""\n    config = obj.__config__\n    prev, config.allow_mutation = config.allow_mutation, True\n    try:\n        yield\n    finally:\n        config.allow_mutation = prev\n\n\ndef migrator(from_: str, to_: str) -> Callable[[MigratorF], MigratorF]:\n    """Decorate function as migrating settings from v `from_` to v `to_`.\n\n    A migrator should mutate a `NapariSettings` model from schema version\n    `from_` to schema version `to_` (in place).\n\n    Parameters\n    ----------\n    from_ : str\n        NapariSettings.schema_version version that this migrator expects as\n        input\n    to_ : str\n        NapariSettings.schema_version version after this migrator has been\n        executed.\n\n    Returns\n    -------\n    Callable[ [MigratorF], MigratorF ]\n        _description_\n    """\n\n    def decorator(migrate_func: MigratorF) -> MigratorF:\n        _from, _to = Version.parse(from_), Version.parse(to_)\n        assert _to >= _from, \'Migrator must increase the version.\'\n        _MIGRATORS.append(Migrator(_from, _to, migrate_func))\n        return migrate_func\n\n    return decorator\n\n\n@migrator(\'0.3.0\', \'0.4.0\')\ndef v030_v040(model: NapariSettings):\n    """Migrate from v0.3.0 to v0.4.0.\n\n    Prior to v0.4.0, npe2 plugins were automatically added to disabled plugins.\n    This migration removes any npe2 plugins discovered in the environment\n    (at migration time) from the "disabled plugins" set.\n    """\n    for dist in distributions():\n        for ep in dist.entry_points:\n            if ep.group == \'napari.manifest\':\n                model.plugins.disabled_plugins.discard(dist.metadata[\'Name\'])\n\n\n@migrator(\'0.4.0\', \'0.5.0\')\ndef v040_050(model: NapariSettings):\n    """Migrate from v0.4.0 to v0.5.0\n\n    Prior to 0.5.0 existing preferences may have reader extensions\n    preferences saved without a leading *.\n    fnmatch would fail on these so we coerce them to include a *\n    e.g. \'.csv\' becomes \'*.csv\'\n    """\n    from napari.settings._utils import _coerce_extensions_to_globs\n\n    current_settings = model.plugins.extension2reader\n    new_settings = _coerce_extensions_to_globs(current_settings)\n    model.plugins.extension2reader = new_settings\n',
            'napari/settings/_napari_settings.py': 'import os\nfrom pathlib import Path\nfrom typing import Any, Optional\n\nfrom napari._pydantic_compat import Field\nfrom napari.settings._appearance import AppearanceSettings\nfrom napari.settings._application import ApplicationSettings\nfrom napari.settings._base import (\n    _NOT_SET,\n    EventedConfigFileSettings,\n    _remove_empty_dicts,\n)\nfrom napari.settings._experimental import ExperimentalSettings\nfrom napari.settings._fields import Version\nfrom napari.settings._plugins import PluginsSettings\nfrom napari.settings._shortcuts import ShortcutsSettings\nfrom napari.utils._base import _DEFAULT_CONFIG_PATH\nfrom napari.utils.translations import trans\n\n_CFG_PATH = os.getenv(\'NAPARI_CONFIG\', _DEFAULT_CONFIG_PATH)\n\nCURRENT_SCHEMA_VERSION = Version(0, 5, 0)\n\n\nclass NapariSettings(EventedConfigFileSettings):\n    """Schema for napari settings."""\n\n    # 1. If you want to *change* the default value of a current option, you need to\n    #    do a MINOR update in config version, e.g. from 3.0.0 to 3.1.0\n    # 2. If you want to *remove* options that are no longer needed in the codebase,\n    #    or if you want to *rename* options, then you need to do a MAJOR update in\n    #    version, e.g. from 3.0.0 to 4.0.0\n    # 3. You don\'t need to touch this value if you\'re just adding a new option\n    schema_version: Version = Field(\n        CURRENT_SCHEMA_VERSION,\n        description=trans._(\'Napari settings schema version.\'),\n    )\n\n    application: ApplicationSettings = Field(\n        default_factory=ApplicationSettings,\n        title=trans._(\'Application\'),\n        description=trans._(\'Main application settings.\'),\n    )\n    appearance: AppearanceSettings = Field(\n        default_factory=AppearanceSettings,\n        title=trans._(\'Appearance\'),\n        description=trans._(\'User interface appearance settings.\'),\n        allow_mutation=False,\n    )\n    plugins: PluginsSettings = Field(\n        default_factory=PluginsSettings,\n        title=trans._(\'Plugins\'),\n        description=trans._(\'Plugins settings.\'),\n        allow_mutation=False,\n    )\n    shortcuts: ShortcutsSettings = Field(\n        default_factory=ShortcutsSettings,\n        title=trans._(\'Shortcuts\'),\n        description=trans._(\'Shortcut settings.\'),\n        allow_mutation=False,\n    )\n    experimental: ExperimentalSettings = Field(\n        default_factory=ExperimentalSettings,\n        title=trans._(\'Experimental\'),\n        description=trans._(\'Experimental settings.\'),\n        allow_mutation=False,\n    )\n\n    # private attributes and ClassVars will not appear in the schema\n    _config_path: Optional[Path] = Path(_CFG_PATH) if _CFG_PATH else None\n\n    class Config(EventedConfigFileSettings.Config):\n        env_prefix = \'napari_\'\n        use_enum_values = False\n        # all of these fields are evented models, so we don\'t want to break\n        # connections by setting the top-level field itself\n        # (you can still mutate attributes in the subfields)\n\n        @classmethod\n        def _config_file_settings_source(cls, settings) -> dict:\n            # before \'0.4.0\' we didn\'t write the schema_version in the file\n            # written to disk. so if it\'s missing, add schema_version of 0.3.0\n            d = super()._config_file_settings_source(settings)\n            d.setdefault(\'schema_version\', \'0.3.0\')\n            return d\n\n    def __init__(self, config_path=_NOT_SET, **values: Any) -> None:\n        super().__init__(config_path, **values)\n        self._maybe_migrate()\n\n    def _save_dict(self, **kwargs):\n        # we always want schema_version written to the settings.yaml\n        # TODO: is there a better way to always include schema version?\n        return {\n            \'schema_version\': self.schema_version,\n            **super()._save_dict(**kwargs),\n        }\n\n    def __str__(self):\n        out = \'NapariSettings (defaults excluded)\\n\' + 34 * \'-\' + \'\\n\'\n        data = self.dict(exclude_defaults=True)\n        out += self._yaml_dump(_remove_empty_dicts(data))\n        return out\n\n    def __repr__(self):\n        return str(self)\n\n    def _maybe_migrate(self):\n        if self.schema_version < CURRENT_SCHEMA_VERSION:\n            from napari.settings._migrations import do_migrations\n\n            do_migrations(self)\n\n\nif __name__ == \'__main__\':\n    import sys\n\n    if len(sys.argv) > 2:\n        dest = Path(sys.argv[2]).expanduser().absolute()\n    else:\n        dest = Path(__file__).parent / \'napari.schema.json\'\n    dest.write_text(NapariSettings.schema_json())\n',
            'napari/settings/_shortcuts.py': "from napari._pydantic_compat import Field, validator\nfrom napari.utils.events.evented_model import EventedModel\nfrom napari.utils.key_bindings import KeyBinding, coerce_keybinding\nfrom napari.utils.shortcuts import default_shortcuts\nfrom napari.utils.translations import trans\n\n\nclass ShortcutsSettings(EventedModel):\n    shortcuts: dict[str, list[KeyBinding]] = Field(\n        default_shortcuts,\n        title=trans._('shortcuts'),\n        description=trans._(\n            'Set keyboard shortcuts for actions.',\n        ),\n    )\n\n    class NapariConfig:\n        # Napari specific configuration\n        preferences_exclude = ('schema_version',)\n\n    @validator('shortcuts', allow_reuse=True)\n    def shortcut_validate(\n        cls, v: dict[str, list[KeyBinding]]\n    ) -> dict[str, list[KeyBinding]]:\n        for name, value in default_shortcuts.items():\n            if name not in v:\n                v[name] = value\n\n        return {\n            name: [coerce_keybinding(kb) for kb in value]\n            for name, value in v.items()\n        }\n",
            'napari/settings/_tests/test_migrations.py': 'import os\nfrom importlib.metadata import PackageNotFoundError, distribution\nfrom unittest.mock import patch\n\nimport pytest\n\nfrom napari.settings import NapariSettings, _migrations\n\n\n@pytest.fixture()\ndef test_migrator(monkeypatch):\n    # this fixture makes sure we\'re not using _migrations.MIGRATORS for tests\n    # but rather only using migrators that get declared IN the test\n    _TEST_MIGRATORS = []\n    with monkeypatch.context() as m:\n        m.setattr(_migrations, \'_MIGRATORS\', _TEST_MIGRATORS)\n        yield _migrations.migrator\n\n\ndef test_no_migrations_available(test_migrator):\n    # no migrators exist... nothing should happen\n    settings = NapariSettings(schema_version=\'0.1.0\')\n    assert settings.schema_version == \'0.1.0\'\n\n\ndef test_backwards_migrator(test_migrator):\n    # we shouldn\'t be able to downgrade the schema version\n    # if that is needed later, we can create a new decorator,\n    # or change this test\n    with pytest.raises(AssertionError):\n\n        @test_migrator(\'0.2.0\', \'0.1.0\')\n        def _(model): ...\n\n\ndef test_migration_works(test_migrator):\n    # test that a basic migrator works to change the version\n    # and mutate the model\n\n    @test_migrator(\'0.1.0\', \'0.2.0\')\n    def _(model: NapariSettings):\n        model.appearance.theme = \'light\'\n\n    settings = NapariSettings(schema_version=\'0.1.0\')\n    assert settings.schema_version == \'0.2.0\'\n    assert settings.appearance.theme == \'light\'\n\n\ndef test_migration_saves(test_migrator):\n    @test_migrator(\'0.1.0\', \'0.2.0\')\n    def _(model: NapariSettings): ...\n\n    with patch.object(NapariSettings, \'save\') as mock:\n        mock.assert_not_called()\n        settings = NapariSettings(config_path=\'junk\', schema_version=\'0.1.0\')\n        assert settings.schema_version == \'0.2.0\'\n        mock.assert_called()\n\n\ndef test_failed_migration_leaves_version(test_migrator):\n    # if an error occurs IN the migrator, the version should stay\n    # where it was before the migration, and any changes reverted.\n    @test_migrator(\'0.1.0\', \'0.2.0\')\n    def _(model: NapariSettings):\n        model.appearance.theme = \'light\'\n        assert model.appearance.theme == \'light\'\n        raise ValueError(\'broken migration\')\n\n    with pytest.warns(UserWarning) as e:\n        settings = NapariSettings(schema_version=\'0.1.0\')\n    assert settings.schema_version == \'0.1.0\'\n    # test migration was atomic, and reverted the theme change\n    assert settings.appearance.theme == \'dark\'\n    # test that the user was warned\n    assert \'Failed to migrate settings from v0.1.0 to v0.2.0\' in str(e[0])\n\n\n@pytest.mark.skipif(\n    bool(os.environ.get(\'MIN_REQ\')), reason=\'not relevant for MIN_REQ\'\n)\ndef test_030_to_040_migration():\n    # Prior to v0.4.0, npe2 plugins were automatically "disabled"\n    # 0.3.0 -> 0.4.0 should remove any installed npe2 plugins from the\n    # set of disabled plugins (see migrator for details)\n    try:\n        d = distribution(\'napari-svg\')\n        assert \'napari.manifest\' in {ep.group for ep in d.entry_points}\n    except PackageNotFoundError:\n        pytest.fail(\n            \'napari-svg not present as an npe2 plugin. \'\n            \'This test needs updating\'\n        )\n\n    settings = NapariSettings(\n        schema_version=\'0.3.0\',\n        plugins={\'disabled_plugins\': {\'napari-svg\', \'napari\'}},\n    )\n    assert \'napari-svg\' not in settings.plugins.disabled_plugins\n    assert \'napari\' not in settings.plugins.disabled_plugins\n\n\n@pytest.mark.skipif(\n    bool(os.environ.get(\'MIN_REQ\')), reason=\'not relevant for MIN_REQ\'\n)\ndef test_040_to_050_migration():\n    # Prior to 0.5.0 existing preferences may have reader extensions\n    # preferences saved without a leading *.\n    # fnmatch would fail on these so we coerce them to include a *\n    # e.g. \'.csv\' becomes \'*.csv\'\n    settings = NapariSettings(\n        schema_version=\'0.4.0\',\n        plugins={\'extension2reader\': {\'.tif\': \'napari\'}},\n    )\n    assert \'.tif\' not in settings.plugins.extension2reader\n    assert \'*.tif\' in settings.plugins.extension2reader\n',
            'napari/settings/_tests/test_settings.py': '"""Tests for the settings manager."""\n\nimport os\nfrom pathlib import Path\n\nimport pytest\nfrom yaml import safe_load\n\nfrom napari import settings\nfrom napari._pydantic_compat import Field, ValidationError\nfrom napari.settings import CURRENT_SCHEMA_VERSION, NapariSettings\nfrom napari.utils.theme import get_theme, register_theme\n\n\n@pytest.fixture()\ndef test_settings(tmp_path):\n    """A fixture that can be used to test and save settings"""\n    from napari.settings import NapariSettings\n\n    class TestSettings(NapariSettings):\n        class Config:\n            env_prefix = \'testnapari_\'\n\n    return TestSettings(\n        tmp_path / \'test_settings.yml\', schema_version=CURRENT_SCHEMA_VERSION\n    )\n\n\ndef test_settings_file(test_settings):\n    assert not Path(test_settings.config_path).exists()\n    test_settings.save()\n    assert Path(test_settings.config_path).exists()\n\n\ndef test_settings_autosave(test_settings):\n    assert not Path(test_settings.config_path).exists()\n    test_settings.appearance.theme = \'light\'\n    assert Path(test_settings.config_path).exists()\n\n\ndef test_settings_file_not_created(test_settings):\n    assert not Path(test_settings.config_path).exists()\n    test_settings._save_on_change = False\n    test_settings.appearance.theme = \'light\'\n    assert not Path(test_settings.config_path).exists()\n\n\ndef test_settings_loads(tmp_path):\n    data = \'appearance:\\n   theme: light\'\n    fake_path = tmp_path / \'fake_path.yml\'\n    fake_path.write_text(data)\n    assert NapariSettings(fake_path).appearance.theme == \'light\'\n\n\ndef test_settings_load_invalid_content(tmp_path):\n    # This is invalid content\n\n    fake_path = tmp_path / \'fake_path.yml\'\n    fake_path.write_text(\':\')\n    NapariSettings(fake_path)\n\n\ndef test_settings_load_invalid_type(tmp_path, caplog):\n    # The invalid data will be replaced by the default value\n    data = \'appearance:\\n   theme: 1\'\n    fake_path = tmp_path / \'fake_path.yml\'\n    fake_path.write_text(data)\n    assert NapariSettings(fake_path).application.save_window_geometry is True\n    assert \'Validation errors in config file\' in str(caplog.records[0])\n\n\ndef test_settings_load_strict(tmp_path, monkeypatch):\n    # use Config.strict_config_check to enforce good config files\n    monkeypatch.setattr(NapariSettings.__config__, \'strict_config_check\', True)\n    data = \'appearance:\\n   theme: 1\'\n    fake_path = tmp_path / \'fake_path.yml\'\n    fake_path.write_text(data)\n    with pytest.raises(ValidationError):\n        NapariSettings(fake_path)\n\n\ndef test_settings_load_invalid_key(tmp_path, monkeypatch):\n    # The invalid key will be removed\n\n    fake_path = tmp_path / \'fake_path.yml\'\n    data = """\n    application:\n       non_existing_key: [1, 2]\n       first_time: false\n    """\n    fake_path.write_text(data)\n\n    monkeypatch.setattr(os, \'environ\', {})\n    s = NapariSettings(fake_path)\n    assert getattr(s, \'non_existing_key\', None) is None\n    s.save()\n    text = fake_path.read_text()\n    # removed bad key\n    assert safe_load(text) == {\n        \'application\': {\'first_time\': False},\n        \'schema_version\': CURRENT_SCHEMA_VERSION,\n    }\n\n\ndef test_settings_load_invalid_section(tmp_path):\n    # The invalid section will be removed from the file\n    data = \'non_existing_section:\\n   foo: bar\'\n\n    fake_path = tmp_path / \'fake_path.yml\'\n    fake_path.write_text(data)\n\n    settings_ = NapariSettings(fake_path)\n    assert getattr(settings_, \'non_existing_section\', None) is None\n\n\ndef test_settings_to_dict(test_settings):\n    data_dict = test_settings.dict()\n    assert isinstance(data_dict, dict)\n    assert data_dict.get(\'application\')\n\n    data_dict = test_settings.dict(exclude_defaults=True)\n    assert not data_dict.get(\'application\')\n\n\ndef test_settings_to_dict_no_env(monkeypatch):\n    """Test that exclude_env works to exclude variables coming from the env."""\n    s = NapariSettings(None, appearance={\'theme\': \'light\'})\n    assert s.dict()[\'appearance\'][\'theme\'] == \'light\'\n    assert s.dict(exclude_env=True)[\'appearance\'][\'theme\'] == \'light\'\n\n    monkeypatch.setenv(\'NAPARI_APPEARANCE_THEME\', \'light\')\n    s = NapariSettings(None)\n    assert s.dict()[\'appearance\'][\'theme\'] == \'light\'\n    assert \'theme\' not in s.dict(exclude_env=True).get(\'appearance\', {})\n\n\ndef test_settings_reset(test_settings):\n    appearance_id = id(test_settings.appearance)\n    test_settings.reset()\n    assert id(test_settings.appearance) == appearance_id\n    assert test_settings.appearance.theme == \'dark\'\n    test_settings.appearance.theme = \'light\'\n    assert test_settings.appearance.theme == \'light\'\n    test_settings.reset()\n    assert test_settings.appearance.theme == \'dark\'\n    assert id(test_settings.appearance) == appearance_id\n\n\ndef test_settings_model(test_settings):\n    with pytest.raises(ValidationError):\n        # Should be string\n        test_settings.appearance.theme = 1\n\n    with pytest.raises(ValidationError):\n        # Should be a valid string\n        test_settings.appearance.theme = \'vaporwave\'\n\n\ndef test_custom_theme_settings(test_settings):\n    # See: https://github.com/napari/napari/issues/2340\n    custom_theme_name = \'_test_blue_\'\n\n    # No theme registered yet, this should fail\n    with pytest.raises(ValidationError):\n        test_settings.appearance.theme = custom_theme_name\n\n    blue_theme = get_theme(\'dark\').to_rgb_dict()\n    blue_theme.update(\n        background=\'rgb(28, 31, 48)\',\n        foreground=\'rgb(45, 52, 71)\',\n        primary=\'rgb(80, 88, 108)\',\n        current=\'rgb(184, 112, 0)\',\n    )\n    register_theme(custom_theme_name, blue_theme, \'test\')\n\n    # Theme registered, should pass validation\n    test_settings.appearance.theme = custom_theme_name\n\n\ndef test_settings_string(test_settings):\n    setstring = str(test_settings)\n    assert \'NapariSettings (defaults excluded)\' in setstring\n    assert \'appearance:\' not in setstring\n    assert repr(test_settings) == setstring\n\n\ndef test_model_fields_are_annotated(test_settings):\n    errors = []\n    for field in test_settings.__fields__.values():\n        model = field.type_\n        if not hasattr(model, \'__fields__\'):\n            continue\n        difference = set(model.__fields__) - set(model.__annotations__)\n        if difference:\n            errors.append(\n                f"Model \'{model.__name__}\' does not provide annotations "\n                f"for the fields:\\n{\', \'.join(repr(f) for f in difference)}"\n            )\n\n    if errors:\n        raise ValueError(\'\\n\\n\'.join(errors))\n\n\ndef test_settings_env_variables(monkeypatch):\n    assert NapariSettings(None).appearance.theme == \'dark\'\n    # NOTE: this was previously tested as NAPARI_THEME\n    monkeypatch.setenv(\'NAPARI_APPEARANCE_THEME\', \'light\')\n    assert NapariSettings(None).appearance.theme == \'light\'\n\n    # can also use json\n    assert NapariSettings(None).application.first_time is True\n    # NOTE: this was previously tested as NAPARI_THEME\n    monkeypatch.setenv(\'NAPARI_APPLICATION\', \'{"first_time": "false"}\')\n    assert NapariSettings(None).application.first_time is False\n\n    # can also use json in nested vars\n    assert NapariSettings(None).plugins.extension2reader == {}\n    monkeypatch.setenv(\'NAPARI_PLUGINS_EXTENSION2READER\', \'{"*.zarr": "hi"}\')\n    assert NapariSettings(None).plugins.extension2reader == {\'*.zarr\': \'hi\'}\n\n\ndef test_settings_env_variables_fails(monkeypatch):\n    monkeypatch.setenv(\'NAPARI_APPEARANCE_THEME\', \'FOOBAR\')\n    with pytest.raises(ValidationError):\n        NapariSettings()\n\n\ndef test_subfield_env_field(monkeypatch):\n    """test that setting Field(env=) works for subfields"""\n    from napari.settings._base import EventedSettings\n\n    class Sub(EventedSettings):\n        x: int = Field(1, env=\'varname\')\n\n    class T(NapariSettings):\n        sub: Sub\n\n    monkeypatch.setenv(\'VARNAME\', \'42\')\n    assert T(sub={}).sub.x == 42\n\n\n# Failing because dark is actually the default...\ndef test_settings_env_variables_do_not_write_to_disk(tmp_path, monkeypatch):\n    # create a settings file with light theme\n    data = \'appearance:\\n   theme: light\'\n    fake_path = tmp_path / \'fake_path.yml\'\n    fake_path.write_text(data)\n\n    # make sure they wrote correctly\n    disk_settings = fake_path.read_text()\n    assert \'theme: light\' in disk_settings\n    # make sure they load correctly\n    assert NapariSettings(fake_path).appearance.theme == \'light\'\n\n    # now load settings again with an Env-var override\n    monkeypatch.setenv(\'NAPARI_APPEARANCE_THEME\', \'dark\')\n    settings = NapariSettings(fake_path)\n    # make sure the override worked, and save again\n    assert settings.appearance.theme == \'dark\'\n    # data from the config file is still "known"\n    assert settings._config_file_settings[\'appearance\'][\'theme\'] == \'light\'\n    # but we know what came from env vars as well:\n    assert settings.env_settings()[\'appearance\'][\'theme\'] == \'dark\'\n\n    # when we save it shouldn\'t use environment variables and it shouldn\'t\n    # have overriden our non-default value of `theme: light`\n    settings.save()\n    disk_settings = fake_path.read_text()\n    assert \'theme: light\' in disk_settings\n\n    # and it\'s back if we reread without the env var override\n    monkeypatch.delenv(\'NAPARI_APPEARANCE_THEME\')\n    assert NapariSettings(fake_path).appearance.theme == \'light\'\n\n\ndef test_settings_only_saves_non_default_values(monkeypatch, tmp_path):\n    from yaml import safe_load\n\n    # prevent error during NAPARI_ASYNC tests\n    monkeypatch.setattr(os, \'environ\', {})\n\n    # manually get all default data and write to yaml file\n    all_data = NapariSettings(None).yaml()\n    fake_path = tmp_path / \'fake_path.yml\'\n    assert \'appearance\' in all_data\n    assert \'application\' in all_data\n    fake_path.write_text(all_data)\n\n    # load that yaml file and resave\n    NapariSettings(fake_path).save()\n\n    # make sure that the only value is now the schema version\n    assert safe_load(fake_path.read_text()) == {\n        \'schema_version\': CURRENT_SCHEMA_VERSION\n    }\n\n\ndef test_get_settings(tmp_path):\n    p = f\'{tmp_path}.yaml\'\n    s = settings.get_settings(p)\n    assert str(s.config_path) == str(p)\n\n\ndef test_get_settings_fails(monkeypatch, tmp_path):\n    p = f\'{tmp_path}.yaml\'\n    settings.get_settings(p)\n    with pytest.raises(\n        RuntimeError, match=\'The path can only be set once per session\'\n    ):\n        settings.get_settings(p)\n\n\ndef test_first_time():\n    """This test just confirms that we don\'t load an existing file (locally)"""\n    assert NapariSettings().application.first_time is True\n\n\n# def test_deprecated_SETTINGS():\n#     """Test that direct access of SETTINGS warns."""\n#     from napari.settings import SETTINGS\n\n#     with pytest.warns(FutureWarning):\n#         assert SETTINGS.appearance.theme == \'dark\'\n\n\ndef test_no_save_path():\n    """trying to save without a config path is an error"""\n    s = NapariSettings(config_path=None)\n    assert s.config_path is None\n\n    with pytest.raises(ValueError, match=\'No path provided\'):\n        # the original `save()` method is patched in conftest._fresh_settings\n        # so we "unmock" it here to assert the failure\n        NapariSettings.__original_save__(s)  # type: ignore\n\n\ndef test_settings_events(test_settings):\n    """Test that NapariSettings emits dotted keys."""\n    from unittest.mock import MagicMock\n\n    mock = MagicMock()\n    test_settings.events.changed.connect(mock)\n    test_settings.appearance.theme = \'light\'\n\n    assert mock.called\n    event = mock.call_args_list[0][0][0]\n    assert event.key == \'appearance.theme\'\n    assert event.value == \'light\'\n\n    mock.reset_mock()\n    test_settings.appearance.theme = \'light\'\n    mock.assert_not_called()\n\n\n@pytest.mark.parametrize(\'ext\', [\'yml\', \'yaml\', \'json\'])\ndef test_full_serialize(test_settings: NapariSettings, tmp_path, ext):\n    """Make sure that every object in the settings is serializeable.\n\n    Should work with both json and yaml.\n    """\n    test_settings.save(tmp_path / f\'t.{ext}\', exclude_defaults=False)\n',
            'napari/utils/key_bindings.py': '"""Key combinations are represented in the form ``[modifier-]key``,\ne.g. ``a``, ``Control-c``, or ``Control-Alt-Delete``.\nValid modifiers are Control, Alt, Shift, and Meta.\n\nLetters will always be read as upper-case.\nDue to the native implementation of the key system, Shift pressed in\ncertain key combinations may yield inconsistent or unexpected results.\nTherefore, it is not recommended to use Shift with non-letter keys. On OSX,\nControl is swapped with Meta such that pressing Command reads as Control.\n\nSpecial keys include Shift, Control, Alt, Meta, Up, Down, Left, Right,\nPageUp, PageDown, Insert, Delete, Home, End, Escape, Backspace, F1,\nF2, F3, F4, F5, F6, F7, F8, F9, F10, F11, F12, Space, Enter, and Tab\n\nFunctions take in only one argument: the parent that the function\nwas bound to.\n\nBy default, all functions are assumed to work on key presses only,\nbut can be denoted to work on release too by separating the function\ninto two statements with the yield keyword::\n\n    @viewer.bind_key(\'h\')\n    def hello_world(viewer):\n        # on key press\n        viewer.status = \'hello world!\'\n\n        yield\n\n        # on key release\n        viewer.status = \'goodbye world :(\'\n\nTo create a keymap that will block others, ``bind_key(..., ...)```.\n"""\n\nimport contextlib\nimport inspect\nimport sys\nimport time\nfrom collections import ChainMap\nfrom collections.abc import Mapping\nfrom types import MethodType\nfrom typing import Callable, Union\n\nfrom app_model.types import KeyBinding, KeyCode, KeyMod\nfrom vispy.util import keys\n\nfrom napari.utils.translations import trans\n\nif sys.version_info >= (3, 10):\n    from types import EllipsisType\nelse:\n    EllipsisType = type(Ellipsis)\n\nKeyBindingLike = Union[KeyBinding, str, int]\nKeymap = Mapping[\n    Union[KeyBinding, EllipsisType], Union[Callable, EllipsisType]\n]\n\n# global user keymap; to be made public later in refactoring process\nUSER_KEYMAP: Mapping[str, Callable] = {}\n\nKEY_SUBS = {\n    \'Control\': \'Ctrl\',\n    \'Option\': \'Alt\',\n}\n\n_UNDEFINED = object()\n\n_VISPY_SPECIAL_KEYS = [\n    keys.SHIFT,\n    keys.CONTROL,\n    keys.ALT,\n    keys.META,\n    keys.UP,\n    keys.DOWN,\n    keys.LEFT,\n    keys.RIGHT,\n    keys.PAGEUP,\n    keys.PAGEDOWN,\n    keys.INSERT,\n    keys.DELETE,\n    keys.HOME,\n    keys.END,\n    keys.ESCAPE,\n    keys.BACKSPACE,\n    keys.F1,\n    keys.F2,\n    keys.F3,\n    keys.F4,\n    keys.F5,\n    keys.F6,\n    keys.F7,\n    keys.F8,\n    keys.F9,\n    keys.F10,\n    keys.F11,\n    keys.F12,\n    keys.SPACE,\n    keys.ENTER,\n    keys.TAB,\n]\n\n_VISPY_MODS = {\n    keys.CONTROL: KeyMod.CtrlCmd,\n    keys.SHIFT: KeyMod.Shift,\n    keys.ALT: KeyMod.Alt,\n    keys.META: KeyMod.WinCtrl,\n}\n\n# TODO: add this to app-model instead\nKeyBinding.__hash__ = lambda self: hash(str(self))\n\n\ndef coerce_keybinding(key_bind: KeyBindingLike) -> KeyBinding:\n    """Convert a keybinding-like object to a KeyBinding.\n\n    Parameters\n    ----------\n    key_bind : keybinding-like\n        Object to coerce.\n\n    Returns\n    -------\n    key_bind : KeyBinding\n        Object as KeyBinding.\n    """\n    if isinstance(key_bind, str):\n        for k, v in KEY_SUBS.items():\n            key_bind = key_bind.replace(k, v)\n\n    return KeyBinding.validate(key_bind)\n\n\ndef bind_key(\n    keymap: Keymap,\n    key_bind: Union[KeyBindingLike, EllipsisType],\n    func=_UNDEFINED,\n    *,\n    overwrite=False,\n):\n    """Bind a key combination to a keymap.\n\n    Parameters\n    ----------\n    keymap : dict of str: callable\n        Keymap to modify.\n    key_bind : keybinding-like or ...\n        Key combination.\n        ``...`` acts as a wildcard if no key combinations can be matched\n        in the keymap (this will overwrite all key combinations\n        further down the lookup chain).\n    func : callable, None, or ...\n        Callable to bind to the key combination.\n        If ``None`` is passed, unbind instead.\n        ``...`` acts as a blocker, effectively unbinding the key\n        combination for all keymaps further down the lookup chain.\n    overwrite : bool, keyword-only, optional\n        Whether to overwrite the key combination if it already exists.\n\n    Returns\n    -------\n    unbound : callable or None\n        Callable unbound by this operation, if any.\n\n    Notes\n    -----\n    Key combinations are represented in the form ``[modifier-]key``,\n    e.g. ``a``, ``Control-c``, or ``Control-Alt-Delete``.\n    Valid modifiers are Control, Alt, Shift, and Meta.\n\n    Letters will always be read as upper-case.\n    Due to the native implementation of the key system, Shift pressed in\n    certain key combinations may yield inconsistent or unexpected results.\n    Therefore, it is not recommended to use Shift with non-letter keys. On OSX,\n    Control is swapped with Meta such that pressing Command reads as Control.\n\n    Special keys include Shift, Control, Alt, Meta, Up, Down, Left, Right,\n    PageUp, PageDown, Insert, Delete, Home, End, Escape, Backspace, F1,\n    F2, F3, F4, F5, F6, F7, F8, F9, F10, F11, F12, Space, Enter, and Tab\n\n    Functions take in only one argument: the parent that the function\n    was bound to.\n\n    By default, all functions are assumed to work on key presses only,\n    but can be denoted to work on release too by separating the function\n    into two statements with the yield keyword::\n\n        @viewer.bind_key(\'h\')\n        def hello_world(viewer):\n            # on key press\n            viewer.status = \'hello world!\'\n\n            yield\n\n            # on key release\n            viewer.status = \'goodbye world :(\'\n\n    To create a keymap that will block others, ``bind_key(..., ...)```.\n    """\n    if func is _UNDEFINED:\n\n        def inner(func):\n            bind_key(keymap, key_bind, func, overwrite=overwrite)\n            return func\n\n        return inner\n\n    if key_bind is not Ellipsis:\n        key_bind = coerce_keybinding(key_bind)\n\n    if func is not None and key_bind in keymap and not overwrite:\n        raise ValueError(\n            trans._(\n                "keybinding {key} already used! specify \'overwrite=True\' to bypass this check",\n                deferred=True,\n                key=str(key_bind),\n            )\n        )\n\n    unbound = keymap.pop(key_bind, None)\n\n    if func is not None:\n        if func is not Ellipsis and not callable(func):\n            raise TypeError(\n                trans._(\n                    "\'func\' must be a callable",\n                    deferred=True,\n                )\n            )\n        keymap[key_bind] = func\n\n    return unbound\n\n\ndef _get_user_keymap() -> Keymap:\n    """Retrieve the current user keymap. The user keymap is global and takes precedent over all other keymaps.\n\n    Returns\n    -------\n    user_keymap : dict of str: callable\n        User keymap.\n    """\n    return USER_KEYMAP\n\n\ndef _bind_user_key(\n    key_bind: KeyBindingLike, func=_UNDEFINED, *, overwrite=False\n):\n    """Bind a key combination to the user keymap.\n\n    See ``bind_key`` docs for details.\n    """\n    return bind_key(_get_user_keymap(), key_bind, func, overwrite=overwrite)\n\n\ndef _vispy2appmodel(event) -> KeyBinding:\n    key, modifiers = event.key.name, event.modifiers\n    if len(key) == 1 and key.isalpha():  # it\'s a letter\n        key = key.upper()\n        cond = lambda m: True  # noqa: E731\n    elif key in _VISPY_SPECIAL_KEYS:\n        # remove redundant information i.e. an output of \'Shift-Shift\'\n        cond = lambda m: m != key  # noqa: E731\n    else:\n        # Shift is consumed to transform key\n\n        # bug found on OSX: Command will cause Shift to not\n        # transform the key so do not consume it\n        # note: \'Control\' is OSX Command key\n        cond = lambda m: m != \'Shift\' or \'Control\' in modifiers  # noqa: E731\n\n    kb = KeyCode.from_string(KEY_SUBS.get(key, key))\n\n    for key in filter(lambda key: key in modifiers and cond(key), _VISPY_MODS):\n        kb |= _VISPY_MODS[key]\n\n    return coerce_keybinding(kb)\n\n\nclass KeybindingDescriptor:\n    """Descriptor which transforms ``func`` into a method with the first\n    argument bound to ``class_keymap`` or ``keymap`` depending on if it was\n    called from the class or the instance, respectively.\n\n    Parameters\n    ----------\n    func : callable\n        Function to bind.\n    """\n\n    def __init__(self, func) -> None:\n        self.__func__ = func\n\n    def __get__(self, instance, cls):\n        keymap = instance.keymap if instance is not None else cls.class_keymap\n        return MethodType(self.__func__, keymap)\n\n\nclass KeymapProvider:\n    """Mix-in to add keymap functionality.\n\n    Attributes\n    ----------\n    class_keymap : dict\n        Class keymap.\n    keymap : dict\n        Instance keymap.\n    """\n\n    def __init__(self, *args, **kwargs) -> None:\n        super().__init__(*args, **kwargs)\n        self._keymap = {}\n\n    @property\n    def keymap(self):\n        return self._keymap\n\n    @keymap.setter\n    def keymap(self, value):\n        self._keymap = {coerce_keybinding(k): v for k, v in value.items()}\n\n    def __init_subclass__(cls, **kwargs):\n        super().__init_subclass__(**kwargs)\n\n        if \'class_keymap\' not in cls.__dict__:\n            # if in __dict__, was defined in class and not inherited\n            cls.class_keymap = {}\n        else:\n            cls.class_keymap = {\n                coerce_keybinding(k): v for k, v in cls.class_keymap.items()\n            }\n\n    bind_key = KeybindingDescriptor(bind_key)\n\n\ndef _bind_keymap(keymap, instance):\n    """Bind all functions in a keymap to an instance.\n\n    Parameters\n    ----------\n    keymap : dict\n        Keymap to bind.\n    instance : object\n        Instance to bind to.\n\n    Returns\n    -------\n    bound_keymap : dict\n        Keymap with functions bound to the instance.\n    """\n    bound_keymap = {\n        key: MethodType(func, instance) if func is not Ellipsis else func\n        for key, func in keymap.items()\n    }\n    return bound_keymap\n\n\nclass KeymapHandler:\n    """Handle key mapping and calling functionality.\n\n    Attributes\n    ----------\n    keymap_providers : list of KeymapProvider\n        Classes that provide the keymaps for this class to handle.\n    """\n\n    def __init__(self) -> None:\n        super().__init__()\n        self._key_release_generators = {}\n        self.keymap_providers = []\n\n    @property\n    def keymap_chain(self):\n        """collections.ChainMap: Chain of keymaps from keymap providers."""\n        maps = [_get_user_keymap()]\n\n        for parent in self.keymap_providers:\n            maps.append(_bind_keymap(parent.keymap, parent))\n            # For parent and superclasses add inherited keybindings\n            for cls in parent.__class__.__mro__:\n                if hasattr(cls, \'class_keymap\'):\n                    maps.append(_bind_keymap(cls.class_keymap, parent))\n\n        return ChainMap(*maps)\n\n    @property\n    def active_keymap(self):\n        """dict: Active keymap, created by resolving the keymap chain."""\n        active_keymap = self.keymap_chain\n        keymaps = active_keymap.maps\n\n        for i, keymap in enumerate(keymaps):\n            if Ellipsis in keymap:  # catch-all key\n                # trim all keymaps after catch-all\n                active_keymap = ChainMap(*keymaps[: i + 1])\n                break\n\n        active_keymap_final = {\n            k: func\n            for k, func in active_keymap.items()\n            if func is not Ellipsis\n        }\n\n        return active_keymap_final\n\n    def press_key(self, key_bind):\n        """Simulate a key press to activate a keybinding.\n\n        Parameters\n        ----------\n        key_bind : keybinding-like\n            Key combination.\n        """\n        key_bind = coerce_keybinding(key_bind)\n        keymap = self.active_keymap\n        if key_bind in keymap:\n            func = keymap[key_bind]\n        elif Ellipsis in keymap:  # catch-all\n            func = keymap[...]\n        else:\n            return  # no keybinding found\n\n        if func is Ellipsis:  # blocker\n            return\n        if not callable(func):\n            raise TypeError(\n                trans._(\n                    \'expected {func} to be callable\',\n                    deferred=True,\n                    func=func,\n                )\n            )\n\n        generator_or_callback = func()\n\n        key = str(key_bind.parts[-1].key)\n\n        if inspect.isgeneratorfunction(func):\n            try:\n                next(generator_or_callback)  # call function\n            except StopIteration:  # only one statement\n                pass\n            else:\n                self._key_release_generators[key] = generator_or_callback\n        if isinstance(generator_or_callback, Callable):\n            self._key_release_generators[key] = (\n                generator_or_callback,\n                time.time(),\n            )\n\n    def release_key(self, key_bind):\n        """Simulate a key release for a keybinding.\n\n        Parameters\n        ----------\n        key_bind : keybinding-like\n            Key combination.\n        """\n        from napari.settings import get_settings\n\n        key_bind = coerce_keybinding(key_bind)\n        key = str(key_bind.parts[-1].key)\n        with contextlib.suppress(KeyError, StopIteration):\n            val = self._key_release_generators[key]\n            # val could be callback function with time to check\n            # if it should be called or generator that need to make\n            # additional step on key release\n            if isinstance(val, tuple):\n                callback, start = val\n                if (\n                    time.time() - start\n                    > get_settings().application.hold_button_delay\n                ):\n                    callback()\n            else:\n                next(val)  # call function\n\n    def on_key_press(self, event):\n        """Called whenever key pressed in canvas.\n\n        Parameters\n        ----------\n        event : vispy.util.event.Event\n            The vispy key press event that triggered this method.\n        """\n        from napari.utils.action_manager import action_manager\n\n        if event.key is None:\n            # TODO determine when None key could be sent.\n            return\n\n        kb = _vispy2appmodel(event)\n\n        repeatables = {\n            *action_manager._get_repeatable_shortcuts(self.keymap_chain),\n            \'Up\',\n            \'Down\',\n            \'Left\',\n            \'Right\',\n        }\n\n        if (\n            event.native is not None\n            and event.native.isAutoRepeat()\n            and kb not in repeatables\n        ) or event.key is None:\n            # pass if no key is present or if the shortcut combo is held down,\n            # unless the combo being held down is one of the autorepeatables or\n            # one of the navigation keys (helps with scrolling).\n            return\n\n        self.press_key(kb)\n\n    def on_key_release(self, event):\n        """Called whenever key released in canvas.\n\n        Parameters\n        ----------\n        event : vispy.util.event.Event\n            The vispy key release event that triggered this method.\n        """\n        if event.key is None or (\n            # on linux press down is treated as multiple press and release\n            event.native is not None and event.native.isAutoRepeat()\n        ):\n            return\n        kb = _vispy2appmodel(event)\n        self.release_key(kb)\n',
        }
